import json

src_file = "extracted_the_gioi.jsonl"
tgt_file = "translated_the_gioi.jsonl"

# 1. Read first 251 lines of target file
with open(tgt_file, "r", encoding="utf-8") as f:
    lines = [line for line in f]

clean_lines = lines[:251]
print(f"Truncated target to {len(clean_lines)} clean lines.")

# 2. Fetch the exact source outputs for our 5 new articles
oconnor_vi = None
f35_vi = None
roundup1_vi = None
monkeypox_vi = None
roundup2_vi = None

kw_oconnor = "Bác sĩ của Nhà Trắng, TS. Kevin O'Connor khẳng định ông Biden không tái phát"
kw_f35 = "Không quân Mỹ đã tạm dừng bay với toàn bộ phi đội tiêm kích tàng hình F-35 Joint Strike Fighter"
kw_roundup1 = "Thống đốc bang Kentucky Andy Beshear cho biết con số này dự kiến tăng lên"
kw_monkeypox = "Tây Ban Nha hiện là một trong những quốc gia bị ảnh hưởng nặng nề nhất trên thế giới về đậu mùa khỉ"
kw_roundup2 = "Tranh cãi về vụ pháo kích nhà tù Olenivka"

with open(src_file, "r", encoding="utf-8") as f:
    for line in f:
        if line.strip():
            data = json.loads(line)
            vi = data.get("output", "")
            if kw_oconnor in vi:
                oconnor_vi = vi
            elif kw_f35 in vi:
                f35_vi = vi
            elif kw_roundup1 in vi:
                roundup1_vi = vi
            elif kw_monkeypox in vi:
                monkeypox_vi = vi
            elif kw_roundup2 in vi:
                if len(vi) > 3000 and "Igor Konashenkov" in vi:
                    roundup2_vi = vi

if not all([oconnor_vi, f35_vi, roundup1_vi, monkeypox_vi, roundup2_vi]):
    print(f"Error fetching source texts! Oconnor={bool(oconnor_vi)}, F35={bool(f35_vi)}, Roundup1={bool(roundup1_vi)}, Monkeypox={bool(monkeypox_vi)}, Roundup2={bool(roundup2_vi)}")
    exit(1)

