# 4. Form new clean objects
new_records = [
    {"topic": "Thế giới", "instruction": "Dịch thuật sang Tiếng việt theo chủ đề Thế giới", "input": oconnor_en, "output": oconnor_vi},
    {"topic": "Thế giới", "instruction": "Dịch thuật sang Tiếng việt theo chủ đề Thế giới", "input": f35_en, "output": f35_vi},
    {"topic": "Thế giới", "instruction": "Dịch thuật sang Tiếng việt theo chủ đề Thế giới", "input": roundup1_en, "output": roundup1_vi},
    {"topic": "Thế giới", "instruction": "Dịch thuật sang Tiếng việt theo chủ đề Thế giới", "input": monkeypox_en, "output": monkeypox_vi},
    {"topic": "Thế giới", "instruction": "Dịch thuật sang Tiếng việt theo chủ đề Thế giới", "input": roundup2_en, "output": roundup2_vi}
]

# 5. Overwrite target file
with open(tgt_file, "w", encoding="utf-8") as f:
    f.writelines(clean_lines)
    for rec in new_records:
        f.write(json.dumps(rec, ensure_ascii=False) + "\n")

print("Successfully restored and re-appended clean translations!")
